#include <stdio.h>
#include <stdint.h>

const int64_t MOD = 998244353LL;

int64_t mod_pow(int64_t a, int64_t e) {
    int64_t res = 1 % MOD;
    a %= MOD;
    while (e) {
        if (e & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        e >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t N, M;
        scanf("%lld %lld", &N, &M);
        int64_t ans = 0;
        int64_t limit = M;
        for (int k = 0; (1LL << k) <= limit; ++k) {
            int64_t period = 1LL << (k + 1);
            int64_t full = (M + 1) / period;
            int64_t rem = (M + 1) % period;
            int64_t cnt = full * (1LL << k) + (rem > (1LL << k) ? rem - (1LL << k) : 0);
            if (cnt == 0) continue;
            int64_t term = mod_pow(cnt % MOD, N);
            term = (term * ((1LL << k) % MOD)) % MOD;
            ans += term;
            if (ans >= MOD) ans -= MOD;
        }
        printf("%lld\n", ans % MOD);
    }
    return 0;
}

