const fs = require('fs');
const MOD = 998244353n;
function modPow(base, exp) {
  base %= MOD;
  let result = 1n;
  while (exp > 0n) {
    if (exp & 1n) result = (result * base) % MOD;
    base = (base * base) % MOD;
    exp >>= 1n;
  }
  return result;
}
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = BigInt(input[idx++]);
  const M = BigInt(input[idx++]);
  let ans = 0n;
  for (let k = 0; (1n << BigInt(k)) <= M; ++k) {
    const bit = 1n << BigInt(k);
    const period = bit << 1n; // 2^{k+1}
    const full = (M + 1n) / period;
    const rem = (M + 1n) % period;
    const cnt = full * bit + (rem > bit ? rem - bit : 0n);
    if (cnt === 0n) continue;
    const term = modPow(cnt % MOD, N) * (bit % MOD) % MOD;
    ans = (ans + term) % MOD;
  }
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));

